 1→import { tool } from "ai";
 2→import { z } from "zod";
 3→import { createEmbeddingVector } from "../../graph/embeddings";
 4→import {
 5→  listEntityNeighbors,
 6→  parseRecordIdString,
 7→  resolveWorkspaceProjectRecord,
 8→  searchEntitiesByEmbedding,
 9→  type GraphEntityTable,
10→  type SearchEntityKind,
11→} from "../../graph/queries";
12→import { requireToolContext } from "./helpers";
13→import type { ChatToolDeps } from "./types";
14→
15→export function createSearchEntitiesTool(deps: ChatToolDeps) {
16→  return tool({
17→    description:
18→      "Search the knowledge graph for entities matching a query. Use this when the user asks about topics, decisions, or tasks not already covered in context.",
19→    inputSchema: z.object({
20→      query: z.string().min(1).describe("Natural language search query"),
21→      kinds: z.array(z.enum(["project", "feature", "task", "decision", "question"]))
22→        .optional()
23→        .describe("Optional filter by entity kinds"),
24→      project: z.string().optional().describe("Optional project name or project record id"),
25→      limit: z.number().int().min(1).max(25).default(10).describe("Maximum number of results"),
26→    }),
27→    execute: async (input, options) => {
28→      const context = requireToolContext(options);
29→      const queryEmbedding = await createEmbeddingVector(deps.embeddingModel, input.query, deps.embeddingDimension);
30→      if (!queryEmbedding) {
31→        throw new Error("failed to create query embedding for search_entities");
32→      }
33→
34→      const projectRecord = input.project
35→        ? await resolveWorkspaceProjectRecord({
36→            surreal: deps.surreal,
37→            workspaceRecord: context.workspaceRecord,
38→            projectInput: input.project,
39→          })
40→        : undefined;
41→
42→      const results = await searchEntitiesByEmbedding({
43→        surreal: deps.surreal,
44→        workspaceRecord: context.workspaceRecord,
45→        queryEmbedding,
46→        ...(input.kinds ? { kinds: input.kinds as SearchEntityKind[] } : {}),
47→        ...(projectRecord ? { projectRecord } : {}),
48→        limit: input.limit,
49→      });
50→
51→      const enriched = await Promise.all(
52→        results.map(async (row) => {
53→          const entityRecord = parseRecordIdString(row.id, [row.kind as GraphEntityTable], row.kind as GraphEntityTable);
54→          const neighbors = await listEntityNeighbors({
55→            surreal: deps.surreal,
56→            workspaceRecord: context.workspaceRecord,
57→            entityRecord,
58→            limit: 8,
59→          });
60→
61→          return {
62→            id: `${row.kind}:${row.id}`,
63→            kind: row.kind,
64→            name: row.name,
65→            confidence: Number(row.score.toFixed(4)),
66→            ...(row.status ? { status: row.status } : {}),
67→            related: neighbors.slice(0, 4).map((neighbor) => ({
68→              id: `${neighbor.kind}:${neighbor.id}`,
69→              kind: neighbor.kind,
70→              name: neighbor.name,
71→              relation: neighbor.relationKind,
72→            })),
73→          };
74→        }),
75→      );
76→
77→      return {
78→        query: input.query,
79→        results: enriched,
80→      };
81→    },
82→  });
83→}
