 17→const resolveDecisionInputSchema = z.object({
 18→  question: z.string().min(1).describe("The decision question"),
 19→  options: z.array(z.string().min(1)).optional().describe("Known options being considered"),
 20→  context: z
 21→    .object({
 22→      project: z.string().optional(),
 23→      feature: z.string().optional(),
 24→    })
 25→    .optional()
 26→    .describe("Optional project/feature scope for searching decisions"),
