 29→export function createCheckConstraintsTool(deps: ChatToolDeps) {
 30→  return tool({
 31→    description:
 32→      "Check if a proposed action conflicts with existing decisions or constraints. Returns hard conflicts, soft tensions, supporting context, and proceed flag.",
 33→    inputSchema: z.object({
 34→      proposed_action: z.string().min(1).describe("What is being proposed"),
 35→      project: z.string().optional().describe("Optional project scope"),
 36→    }),
 37→    execute: async (input, options) => {
 38→      const context = requireToolContext(options);
 39→      const queryEmbedding = await createEmbeddingVector(
 40→        deps.embeddingModel,
 41→        input.proposed_action,
 42→        deps.embeddingDimension,
 43→      );
 44→      if (!queryEmbedding) {
 45→        throw new Error("failed to create query embedding for check_constraints");
 46→      }
 47→
 48→      const projectRecord = input.project
 49→        ? await resolveWorkspaceProjectRecord({
 50→            surreal: deps.surreal,
 51→            workspaceRecord: context.workspaceRecord,
 52→            projectInput: input.project,
 53→          })
 54→        : undefined;
 55→
 56→      const candidates = await listDecisionConstraintCandidates({
 57→        surreal: deps.surreal,
 58→        workspaceRecord: context.workspaceRecord,
 59→        queryEmbedding,
 60→        ...(projectRecord ? { projectRecord } : {}),
 61→        limit: 14,
 62→      });
 63→
 64→      const actionTokens = normalizeTokens(input.proposed_action);
 65→      const hardConflicts: Array<{ id: string; name: string; score: number; reason: string }> = [];
 66→      const softTensions: Array<{ id: string; name: string; score: number; reason: string }> = [];
 67→      const supporting: Array<{ id: string; name: string; score: number; reason: string }> = [];
 68→
 69→      for (const candidate of candidates) {
 70→        const candidateTokens = normalizeTokens(candidate.name);
 71→        const overlap = hasTokenOverlap(actionTokens, candidateTokens);
 72→        const status = candidate.status?.toLowerCase();
 73→
 74→        if (candidate.kind === "decision" && overlap && (status === "contested" || status === "superseded")) {
 75→          hardConflicts.push({
 76→            id: `${candidate.kind}:${candidate.id}`,
 77→            name: candidate.name,
 78→            score: Number(candidate.score.toFixed(4)),
 79→            reason: `Decision is marked ${status}.`,
 80→          });
 81→          continue;
 82→        }
 83→
 84→        if (candidate.kind === "decision" && candidate.score >= 0.86 && overlap) {
 85→          supporting.push({
 86→            id: `${candidate.kind}:${candidate.id}`,
 87→            name: candidate.name,
 88→            score: Number(candidate.score.toFixed(4)),
 89→            reason: "High-similarity decision aligns with proposed action.",
 90→          });
 91→          continue;
 92→        }
 93→
 94→        if (candidate.score >= 0.72) {
 95→          softTensions.push({
 96→            id: `${candidate.kind}:${candidate.id}`,
 97→            name: candidate.name,
 98→            score: Number(candidate.score.toFixed(4)),
 99→            reason: overlap
100→              ? "Related decision/question may require consistency checks."
101→              : "Semantically related context may be affected.",
102→          });
103→        }
104→      }
105→
106→      return {
107→        hard_conflicts: hardConflicts,
108→        soft_tensions: softTensions,
109→        supporting,
110→        proceed: hardConflicts.length === 0,
111→      };
112→    },
113→  });
114→}
