export function createInvokePmAgentTool(deps: OrchestratorToolDeps) {
  return tool({
    description: [
      "Invoke the PM subagent — the single authority on tasks, features, and project status.",
      "Pick intent by user signal:",
      "- plan_work: user discusses goals, features, or work to be done.",
      "- check_status: user asks about progress, blockers, or project status.",
